#include<bits/stdc++.h>
using namespace std;
vector<long long> mp[1000010];
long long ans,val[1000010],fa[1000010],f[1000010][2],root,n;
bool vis[1000010];
void dp(long long x)
{
    vis[x]=1;
    f[x][0]=0;
    f[x][1]=val[x];
    for(long long i:mp[x])
    {
        if(i!=root)
        {
            dp(i);
            f[x][0]+=max(f[i][0],f[i][1]);
            f[x][1]+=f[i][0];
        }
    }
}
long long solve(long long x)
{
    root=x;
    while(!vis[root])
    {
        vis[root]=1;
        root=fa[root];
    }
    dp(root);
    long long tmp=f[root][0];
    root=fa[root];
    dp(root);
    tmp=max(tmp,f[root][0]);
    return tmp;
}
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld%lld",&val[i],&fa[i]);
        mp[fa[i]].push_back(i);
    }
    for(long long i=1;i<=n;i++)
    {
        if(!vis[i])
        {
            ans+=solve(i);
        }
    }
    printf("%lld",ans);
    return 0;
}
